code.Java:
import java.util.*;

public class Main {
    static long[] dp = new long[31]; // N ≤ 30

    static long fib(int n) {
        if (n == 1) return 0;
        if (n == 2) return 1;
        if (dp[n] != -1) return dp[n];
        dp[n] = fib(n - 1) + fib(n - 2);
        return dp[n];
    }

    public static void main(String[] args) {
        Arrays.fill(dp, -1);
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            System.out.println(fib(n));
        }
        sc.close();
    }
}

