import sys

dp = {}

def fib(n: int) -> int:
    if n == 1:
        return 0
    if n == 2:
        return 1
    if n in dp:
        return dp[n]
    dp[n] = fib(n - 1) + fib(n - 2)
    return dp[n]

data = sys.stdin.read().strip().split()
if not data:
    sys.exit()
T = int(data[0])
idx = 1
out = []
for _ in range(T):
    n = int(data[idx])
    idx += 1
    out.append(str(fib(n)))
print('\n'.join(out))

